/**
 * BNCP News UI Patch v2
 *
 * Purpose:
 * - Make Domestic / Overseas / SNS / COM buttons load JSON files generated by GitHub Actions.
 * - Works even when buttons are created later by app.js.
 *
 * Required in index.html, before </body>:
 *   <script src="./assets/news-patch.js" defer></script>
 */

(function () {
  const CATEGORY_FILES = {
    domestic: "./data/domestic-news.json",
    overseas: "./data/overseas-news.json",
    sns: "./data/sns-news.json",
    com: "./data/com-news.json"
  };

  const CATEGORY_LABELS = {
    domestic: "국내 언론",
    overseas: "해외 언론",
    sns: "SNS",
    com: "COM"
  };

  function cleanText(value) {
    return String(value || "").replace(/\s+/g, "").toLowerCase();
  }

  function detectCategoryFromElement(el) {
    if (!el) return null;

    let cur = el;
    for (let depth = 0; cur && depth < 4; depth++, cur = cur.parentElement) {
      const raw = [
        cur.id,
        cur.className,
        cur.getAttribute?.("data-category"),
        cur.getAttribute?.("data-news-category"),
        cur.getAttribute?.("data-filter"),
        cur.getAttribute?.("aria-label"),
        cur.textContent
      ].join(" ");

      const text = cleanText(raw);

      if (text.includes("domestic") || text.includes("korea") || text.includes("국내언론") || text.includes("국내")) return "domestic";
      if (text.includes("overseas") || text.includes("global") || text.includes("world") || text.includes("foreign") || text.includes("해외언론") || text.includes("해외")) return "overseas";
      if (text.includes("sns") || text.includes("social") || text.includes("소셜")) return "sns";
      if (text.includes("com") || text.includes("cabinet") || text.includes("council") || text.includes("مجلس")) return "com";
    }

    return null;
  }

  function installStyles() {
    if (document.getElementById("bncpNewsPatchStyle")) return;

    const style = document.createElement("style");
    style.id = "bncpNewsPatchStyle";
    style.textContent = `
      #bncp-news-results {
        box-sizing: border-box;
        width: min(1120px, calc(100% - 32px));
        margin: 28px auto;
        padding: 0;
        font-family: inherit;
      }
      .bncp-news-panel {
        width: 100%;
        box-sizing: border-box;
      }
      .bncp-news-header {
        margin-bottom: 16px;
      }
      .bncp-news-header h2 {
        margin: 0 0 6px 0;
        font-size: 24px;
        font-weight: 800;
        line-height: 1.3;
      }
      .bncp-news-muted {
        color: #6b7280;
        margin: 0;
        font-size: 14px;
        line-height: 1.5;
      }
      .bncp-news-list {
        display: grid;
        gap: 12px;
      }
      .bncp-news-card {
        border: 1px solid rgba(17, 24, 39, 0.12);
        border-radius: 14px;
        padding: 16px;
        background: #fff;
        box-shadow: 0 6px 18px rgba(17, 24, 39, 0.06);
      }
      .bncp-news-title {
        display: block;
        color: #111827;
        text-decoration: none;
        font-size: 17px;
        line-height: 1.45;
        font-weight: 800;
      }
      .bncp-news-title:hover {
        text-decoration: underline;
      }
      .bncp-news-meta {
        display: flex;
        flex-wrap: wrap;
        gap: 8px 12px;
        margin-top: 8px;
        color: #6b7280;
        font-size: 13px;
      }
      .bncp-news-query {
        color: #f37321;
        font-weight: 700;
      }
      .bncp-news-desc {
        margin: 10px 0 0 0;
        color: #374151;
        font-size: 14px;
        line-height: 1.55;
      }
      body.dark .bncp-news-card,
      [data-theme="dark"] .bncp-news-card {
        background: #111827;
        border-color: rgba(255,255,255,0.16);
      }
      body.dark .bncp-news-title,
      [data-theme="dark"] .bncp-news-title {
        color: #f9fafb;
      }
      body.dark .bncp-news-desc,
      [data-theme="dark"] .bncp-news-desc {
        color: #d1d5db;
      }
    `;
    document.head.appendChild(style);
  }

  function ensureContainer(clickedEl) {
    installStyles();

    let container =
      document.querySelector("#bncp-news-results") ||
      document.querySelector("[data-news-list]") ||
      document.querySelector("#news-list") ||
      document.querySelector("#newsList") ||
      document.querySelector("#articles") ||
      document.querySelector("#article-list");

    if (container) return container;

    container = document.createElement("section");
    container.id = "bncp-news-results";
    container.setAttribute("aria-live", "polite");

    const anchor =
      clickedEl?.closest?.(".tabs, .section-tabs, .filters, .filter-bar, nav, header, section") ||
      document.querySelector("header") ||
      document.querySelector("main");

    if (anchor && anchor.parentElement) {
      anchor.parentElement.insertBefore(container, anchor.nextSibling);
    } else {
      document.body.appendChild(container);
    }

    return container;
  }

  function formatDate(value) {
    if (!value) return "";
    const d = new Date(value);
    if (Number.isNaN(d.getTime())) return "";
    return new Intl.DateTimeFormat("ko-KR", {
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit"
    }).format(d);
  }

  function escapeHtml(s) {
    return String(s || "").replace(/[&<>"']/g, (ch) => ({
      "&": "&amp;",
      "<": "&lt;",
      ">": "&gt;",
      '"': "&quot;",
      "'": "&#39;"
    }[ch]));
  }

  function renderMessage(container, category, title, message) {
    container.innerHTML = `
      <section class="bncp-news-panel">
        <div class="bncp-news-header">
          <h2>${escapeHtml(title || CATEGORY_LABELS[category] || category)}</h2>
          <p class="bncp-news-muted">${escapeHtml(message)}</p>
        </div>
      </section>
    `;
    container.scrollIntoView({ behavior: "smooth", block: "start" });
  }

  function renderArticles(container, category, payload) {
    const articles = Array.isArray(payload?.articles) ? payload.articles : [];
    const label = CATEGORY_LABELS[category] || category;

    if (!articles.length) {
      renderMessage(
        container,
        category,
        label,
        `${label} 결과가 없습니다. data/${category}-news.json의 count와 articles를 확인하세요.`
      );
      return;
    }

    const cards = articles.map((item) => `
      <article class="bncp-news-card">
        <a class="bncp-news-title" href="${escapeHtml(item.url)}" target="_blank" rel="noopener noreferrer">
          ${escapeHtml(item.title)}
        </a>
        <div class="bncp-news-meta">
          <span>${escapeHtml(item.source || "출처 미상")}</span>
          <span>${escapeHtml(formatDate(item.publishedAt))}</span>
          ${item.query ? `<span class="bncp-news-query">${escapeHtml(item.query)}</span>` : ""}
        </div>
        ${item.description ? `<p class="bncp-news-desc">${escapeHtml(item.description)}</p>` : ""}
      </article>
    `).join("");

    container.innerHTML = `
      <section class="bncp-news-panel">
        <div class="bncp-news-header">
          <h2>${escapeHtml(label)}</h2>
          <p class="bncp-news-muted">
            ${articles.length}건 · 업데이트 ${escapeHtml(formatDate(payload.generatedAt))}
          </p>
        </div>
        <div class="bncp-news-list">${cards}</div>
      </section>
    `;
    container.scrollIntoView({ behavior: "smooth", block: "start" });
  }

  async function loadCategory(category, clickedEl) {
    const container = ensureContainer(clickedEl);
    const file = CATEGORY_FILES[category];

    if (!file) {
      renderMessage(container, category, "오류", "알 수 없는 뉴스 카테고리입니다.");
      return;
    }

    renderMessage(container, category, CATEGORY_LABELS[category], "뉴스 데이터를 불러오는 중입니다...");

    try {
      const response = await fetch(`${file}?v=${Date.now()}`, { cache: "no-store" });
      if (!response.ok) throw new Error(`${response.status} ${response.statusText}`);

      const payload = await response.json();
      console.info("[BNCP News Patch v2]", category, payload);
      renderArticles(container, category, payload);
    } catch (err) {
      console.error("[BNCP News Patch v2] failed", category, err);
      renderMessage(
        container,
        category,
        CATEGORY_LABELS[category],
        `${file} 파일을 불러오지 못했습니다. GitHub Pages 배포 상태와 파일 경로를 확인하세요. 오류: ${err.message || err}`
      );
    }
  }

  // Event delegation: works even if app.js creates buttons after page load.
  document.addEventListener("click", function (event) {
    const clickable = event.target.closest?.("button, a, [role='button'], .tab, .filter, .category, [data-category], [data-news-category]");
    if (!clickable) return;

    const category = detectCategoryFromElement(clickable);
    if (!category) return;

    event.preventDefault();
    event.stopPropagation();
    loadCategory(category, clickable);
  }, true);

  function markDetectedButtons() {
    document.querySelectorAll("button, a, [role='button'], .tab, .filter, .category, [data-category], [data-news-category]").forEach((el) => {
      const category = detectCategoryFromElement(el);
      if (category) el.setAttribute("data-news-category", category);
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", markDetectedButtons);
  } else {
    markDetectedButtons();
  }

  window.BNCPNewsPatch = { loadCategory };
  console.info("[BNCP News Patch v2] loaded");
})();
